#include <bits/stdc++.h>

using namespace std;

// Function to count the number of pairs in the array 
// that satisfy the condition based on the difference with 'z'.
int pairs(int elementlst[], int n, int z) {
    int count = 0; // Variable to keep track of the valid pairs count.

    // Loop through each element in the array.
    for (int i = 0; i < n; i++) {
        int a = elementlst[i]; // Current element.
        int id1 = i; // Pointer for checking elements before the current element.
        int id2 = i; // Pointer for checking elements after the current element.

        // If we are at the first element of the array.
        if (i == 0) {
            // Move `id2` to the last occurrence of the current element.
            while (elementlst[id2 + 1] == a)
                id2 += 1;

            // Check if the next element is within the range [a - z, a + z].
            if (elementlst[id2 + 1] <= a + z && elementlst[id2 + 1] >= a - z)
                count += 1; // Increment count if the condition is satisfied.
        }
        // If we are at any middle element in the array.
        else if (i < n - 1) {
            // Move `id2` to the last occurrence of the current element.
            while (elementlst[id2 + 1] == a)
                id2 += 1;

            // Move `id1` to the first occurrence of the current element.
            while (elementlst[id1 - 1] == a)
                id1 -= 1;

            // Check if either the previous or next element is within the range [a - z, a + z].
            if (((elementlst[id1 - 1] <= a + z) && (elementlst[id1 - 1] >= a - z)) || 
                ((elementlst[id2 + 1] <= a + z) && (elementlst[id2 + 1] >= a - z)))
                count += 1; // Increment count if the condition is satisfied.
        }
        // If we are at the last element of the array.
        else {
            // Move `id1` to the first occurrence of the current element.
            while (elementlst[id1 - 1] == a)
                id1 -= 1;

            // Check if the previous element is within the range [a - z, a + z].
            if (elementlst[id1 - 1] <= a + z && elementlst[id1 - 1] >= a - z)
                count += 1; // Increment count if the condition is satisfied.
        }
    }

    return count; // Return the total count of valid pairs.
}

int main() {
    int n, z; // `n` is the number of elements in the array, `z` is the difference limit.
    cin >> n >> z; // Read the input values for `n` and `z`.

    int elementlst[n]; // Array to store the elements.

    // Read the input values for the array.
    for (int i = 0; i < n; i++) {
        cin >> elementlst[i];
    }

    // Sort the array in non-decreasing order.
    sort(elementlst, elementlst + n);

    // Call the `pairs` function to count the valid pairs and print the result.
    cout << pairs(elementlst, n, z);

    return 0;
}

