#include <stdio.h>
#include <stdlib.h>

// Comparison function for qsort
int compare(const void* a, const void* b) {
    return (*(int*)a - *(int*)b);
}

// Function to count pairs in the list based on the given conditions
int pairs(int elementlst[], int n, int z) {
    int count = 0; // Initialize count of pairs

    // Iterate through each element in the array
    for (int i = 0; i < n; i++) {
        int a = elementlst[i]; // Current element
        int id1 = i; // Initialize left index
        int id2 = i; // Initialize right index

        // If we are at the first element
        if (i == 0) {
            // Move the right index to the last occurrence of the current element
            while (elementlst[id2 + 1] == a) {
                id2 += 1;
            }
            // Check if the next element is within the range of a + z and a - z
            if (elementlst[id2 + 1] <= a + z && elementlst[id2 + 1] >= a - z) {
                count += 1; // Increment count if condition is satisfied
            }
        }
        // If we are in the middle of the array
        else if (i < n - 1) {
            // Move the right index to the last occurrence of the current element
            while (elementlst[id2 + 1] == a) {
                id2 += 1;
            }
            // Move the left index to the first occurrence of the current element
            while (elementlst[id1 - 1] == a) {
                id1 -= 1;
            }
            // Check the neighbors for conditions
            if (((elementlst[id1 - 1] <= a + z) && (elementlst[id1 - 1] >= a - z)) || 
                ((elementlst[id2 + 1] <= a + z) && (elementlst[id2 + 1] >= a - z))) {
                count += 1; // Increment count if condition is satisfied
            }
        }
        // If we are at the last element
        else {
            // Move the left index to the first occurrence of the current element
            while (elementlst[id1 - 1] == a) {
                id1 -= 1;
            }
            // Check if the previous element is within the range of a + z and a - z
            if (elementlst[id1 - 1] <= a + z && elementlst[id1 - 1] >= a - z) {
                count += 1; // Increment count if condition is satisfied
            }
        }
    }
    return count; // Return the total count of pairs
}

// Main function
int main() {
    int n, z; // Declare variables for number of elements and z value
    scanf("%d %d", &n, &z); // Read the number of elements and z value
    int* elementlst = (int*)malloc(n * sizeof(int)); // Dynamically allocate memory for the array

    // Read elements into the array
    for (int i = 0; i < n; i++) {
        scanf("%d", &elementlst[i]);
    }

    // Sort the array
    qsort(elementlst, n, sizeof(int), (int (*)(const void*, const void*)) compare);

    // Call the pairs function and print the result
    printf("%d\n", pairs(elementlst, n, z));

    // Free the allocated memory
    free(elementlst);

    return 0;
}

